// Save login details in a cookie
function setRememberMe(username, passwordHash) {
  const expiryDate = new Date();
  expiryDate.setDate(expiryDate.getDate() + 30);
  document.cookie = `rememberMe=${encodeURIComponent(username)}|${encodeURIComponent(passwordHash)};expires=${expiryDate.toUTCString()};path=/`;
}

// Retrieve login details from the cookie
function getRememberMe() {
  const cookies = document.cookie.split('; ');
  for (let i = 0; i < cookies.length; i++) {
    const parts = cookies[i].split('=');
    if (parts[0] === 'rememberMe') {
      const [username, passwordHash] = decodeURIComponent(parts[1]).split('|');
      return { username, passwordHash };
    }
  }
  return null;
}

// Auto-login if 'Remember Me' cookie is present
function autoLogin() {
  const rememberMeData = getRememberMe();
  if (rememberMeData) {
    const { username, passwordHash } = rememberMeData;
    // Implement auto-login logic here using username and passwordHash
    console.log('Auto-login with:', username, passwordHash);
  }
}

